clean-code-principles.code:
// Используйте осмысленные имена — выбирайте имена, раскрывающие намерение
// Плохо: function d(a, b) { return a - b; }
// Хорошо: function calculateRemaining(budget, spent) { return budget - spent; }

// DRY — не повторяйтесь
// KISS — будьте проще
// Single Responsibility — каждая функция должна делать одно дело

